import{_ as a,o as l,c as r,a5 as s}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"教程 0036：UPS 参数保存触发策略","description":"","frontmatter":{"title":"教程 0036：UPS 参数保存触发策略","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0036-ups-parameter-save-scheduler.html","status":"learning","visibility":"public","summary":"Imported from 0036-ups-parameter-save-scheduler.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0036-ups-parameter-save-scheduler.md","filePath":"content/power/lessons/0036-ups-parameter-save-scheduler.md","lastUpdated":null}'),p={name:"content/power/lessons/0036-ups-parameter-save-scheduler.md"};function t(o,e,i,d,c,n){return l(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="教程-0036-ups-参数保存触发策略" tabindex="-1">教程 0036：UPS 参数保存触发策略 <a class="header-anchor" href="#教程-0036-ups-参数保存触发策略" aria-label="Permalink to &quot;教程 0036：UPS 参数保存触发策略&quot;">​</a></h1><p>中文主讲。一个概念：参数被修改后，不要每写一次就保存一次，而是用脏标志、延时提交和最小保存间隔合并保存。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学保存触发策略，不包含公司内部保存策略、Flash 地址、客户项目参数、内部磨损均衡算法或真实产品掉电保护方案。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>参数保存触发策略（parameter save scheduler）决定“参数被改了以后，什么时候真正写入非易失存储（non-volatile memory / NVM）”。它连接上一节的参数保存（parameter storage）模块，但不等于保存格式本身。</p><p>本课只讲一个概念：通信或本地逻辑修改参数后，先置位脏标志（dirty flag），再经过延时提交（delayed commit）和最小保存间隔（minimum save interval）判断，最后才触发一次 NVM 保存。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>如果每次参数写入都立刻执行 Flash 擦写（Flash erase/write），会带来三个问题：保存次数过多、连续写多个参数时产生重复保存、参数写入路径和存储驱动耦合太紧。</p><p>UPS 参数管理更需要“可解释的保存时机”：哪些写入发生了、什么时候被合并、最终保存了几次。这些证据适合用仿真波形和 C 代码输出向导师提问。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>脏标志像便签上的“这页改过了”。延时提交像等你停止连续修改后再拍照存档。最小保存间隔像规定“就算又改了，也不能太频繁地拿橡皮和钢笔重写同一页”，避免把存储器当成 RAM 一样频繁写。</p><p>本课的例子里，0 ms 和 20 ms 连续两次参数写入，只产生一次 80 ms 的 NVM 保存。这样可以看清“多次写入合并成一次保存”的主线。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>should_save = dirty == 1 and now_ms - last_change_ms &gt;= commit_delay_ms and now_ms - last_save_ms &gt;= minimum_save_interval_ms</p><p>on_saved: dirty = 0 last_save_ms = now_ms save_count = save_count + 1</p><p>其中 <code>last_change_ms</code> 是最近一次参数变化时间，<code>last_save_ms</code> 是最近一次保存时间。40 ms 时距离 20 ms 的最近写入只有 20 ms，不满足 50 ms 延时提交；80 ms 时距离最近写入已有 60 ms，因此可以保存。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_parameter_save_scheduler.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_parameter_save_scheduler.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_parameter_save_scheduler.png</code></p></li><li><p>终端输出：<code>parameter writes: 2</code>、<code>nvm saves: 1</code>、<code>dirty cleared after save: True</code>。</p></li><li><p>图内包含参数框、图例、写入脉冲、保存脉冲、脏标志和保存次数。</p></li></ul><p>观察顺序：先看 0 ms 和 20 ms 的写入脉冲；再看 <code>dirty flag</code> 保持为 1；最后看 80 ms 的保存脉冲出现后，<code>dirty flag</code> 清零，<code>save_count</code> 变成 1。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsParameterSaveScheduler</code>：保存触发状态。</p></li><li><p><code>dirty</code>：有参数未保存。</p></li><li><p><code>last_change_ms</code>：最近一次参数变化时间。</p></li><li><p><code>last_save_ms</code>：最近一次成功保存时间。</p></li><li><p><code>save_count</code>：教学统计，用来确认保存次数。</p></li><li><p><code>UpsParameterSaveScheduler_Init()</code>：初始化调度器。</p></li><li><p><code>UpsParameterSaveScheduler_MarkDirty()</code>：参数被接受写入后置脏。</p></li><li><p><code>UpsParameterSaveScheduler_ShouldSave()</code>：根据当前时间、延时提交和最小保存间隔判断是否保存。</p></li><li><p><code>UpsParameterSaveScheduler_OnSaved()</code>：保存成功后清脏并更新时间。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**参数一写入就必须马上保存。 **纠正：**很多场景应先置脏，再合并保存。</p></li><li><p>**误解：**只要加延时提交就足够。 **纠正：**还需要最小保存间隔，避免频繁保存。</p></li><li><p>**误解：**保存触发策略就是公司真实 Flash 策略。 **纠正：**本课不包含公司内部保存策略，只讲可迁移的通用结构。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_parameter_save_scheduler.py --no-open</code> 并打开 <code>simulations/results/ups_parameter_save_scheduler.png</code>。</p></li><li><p>能解释脏标志、延时提交和最小保存间隔分别解决什么问题。</p></li><li><p>能根据公式判断 40 ms 为什么不保存、80 ms 为什么保存。</p></li><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>parameter_save_scheduler</code> 输出。</p></li><li><p>能基于 <code>parameter_save_scheduler.c -&gt; UpsParameterSaveScheduler_ShouldSave()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么 0 ms 写入后不能马上把 <code>dirty</code> 清掉？</p></li><li><p>为什么 20 ms 再次写入会推迟保存时机？</p></li><li><p>如果通信连续改 5 个参数，保存触发策略应该关注“写入次数”还是“最终一致的参数快照”？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>simulations/results/ups_parameter_save_scheduler.png</code> 看到 0 ms 和 20 ms 两次写入只合并成 80 ms 一次保存。真实工程阅读时，通常从哪个函数看“参数写入”和“保存触发”的边界？</p></li><li><p>我用 <code>parameter_save_scheduler.c -&gt; UpsParameterSaveScheduler_ShouldSave()</code> 只检查 dirty、延时提交和最小保存间隔。真实工程里还会不会受系统模式、故障状态或掉电检测影响？</p></li><li><p>我不会记录公司内部保存策略，只想确认阅读顺序：应先看参数写入入口、保存调度入口，还是 NVM 驱动回调？</p></li></ul><p>**下一步：**可以继续补“参数保存失败与重试边界”，但仍只用教学策略，不记录真实产品内部实现。</p><p>关联：<a href="./0035-ups-parameter-storage.html">上一节：参数保存与默认值恢复</a>；源稿：<code>concepts/embedded/ups-parameter-save-scheduler.md</code>；仿真：<code>simulations/python/ups_parameter_save_scheduler.py</code>。</p><pre><code>上一节：教程 0035：UPS 参数保存与默认值恢复
下一节：教程 0037：三相功率与 dq 坐标变换
</code></pre>`,39)])])}const h=a(p,[["render",t]]);export{m as __pageData,h as default};
